fn prefer_windows_file_task_siblings_inner(file_tasks: Vec<Task>) -> Vec<Task> {
    let windows_exts = Settings::get()
        .windows_executable_extensions
        .iter()
        .map(|ext| ext.to_lowercase())
        .collect::<IndexSet<_>>();
